import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface StorageData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    storage: {
      totalSpace: string;
      usedSpace: string;
      freeSpace: string;
    };
    fileTypeBreakdown: {
      type: string;
      value: number;
    }[];
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const storageData = response.data as StorageData;
  const { storage, fileTypeBreakdown } = storageData.data;
  const { primaryColor, accentColor } = storageData.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 350,
        maxWidth: 450,
        bgcolor: '#1A202C',
        color: '#E2E8F0',
      }}
      elevation={3}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              Storage Usage
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total: {storage.totalSpace}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Used: {storage.usedSpace}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Free: {storage.freeSpace}
            </Typography>
          </Box>

          <PieChart
            height={200}
            series={[
              {
                data: fileTypeBreakdown.map(({ type, value }) => ({
                  label: type,
                  value,
                })),
                color: [primaryColor, accentColor, '#4299E1', '#9F7AEA', '#F6E05E'],
              },
            ]}
            sx={{
              '& .MuiPieArcLabel-root': {
                fontSize: 12,
                fill: '#F7FAFC',
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
